#include<bits/stdc++.h>
using namespace std;
vector<int> mp[100010];
int dfn[100010],siz[100010],d[100010],son[100010],fa[100010],dfncnt,top[100010],rnk[100010],val[100010];
void dfs1(int x,int f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(int i:mp[x])
    {
        if(i!=f)
        {
            d[i]=d[x]+1;
            fa[i]=x;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(int x,int t)
{
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    top[x]=t;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(int i:mp[x])
        {
            if(i!=son[x]&&i!=fa[x])
            {
                dfs2(i,i);
            }
        }
    }
}
struct segement_tree
{
    struct node
    {
        int sum,l,r,lson,rson;
    }a[300010];
    int cnt;
    segement_tree():cnt(0){}
    void pushup(int x)
    {
        a[x].sum=((a[a[x].lson].sum)^(a[a[x].rson].sum));
    }
    int build(int l,int r)
    {
        int x=++cnt;
        a[x].l=l,a[x].r=r;
        if(l==r)
        {
            a[x].sum=val[rnk[l]];
            return x;
        }
        int mid=((l+r)>>1);
        a[x].lson=build(l,mid);
        a[x].rson=build(mid+1,r);
        pushup(x);
        return x;
    }
    void update(int x,int p,int v)
    {
        int l=a[x].l,r=a[x].r;
        if(l>p||r<p)
        {
            return;
        }
        if(l==r)
        {
            a[x].sum=v;
            return;
        }
        update(a[x].lson,p,v);
        update(a[x].rson,p,v);
        pushup(x);
    }
    int query(int x,int l,int r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        return((query(a[x].lson,l,r))^(query(a[x].rson,l,r)));
    }
}t;
int query(int x,int y)
{
    int ans=0;
    int tx=top[x],ty=top[y];
    while(tx!=ty)
    {
        if(d[tx]>=d[ty])
        {
            ans^=t.query(1,dfn[tx],dfn[x]);
            x=fa[tx];
        }
        else
        {
            ans^=t.query(1,dfn[ty],dfn[y]);
            y=fa[ty];
        }
        tx=top[x];
        ty=top[y];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans^=t.query(1,dfn[x],dfn[y]);
    return ans;
}
int main()
{
    int n,q;
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&val[i]);
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs1(1);
    dfs2(1,1);
    t.build(1,n);
    while(q--)
    {
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        if(op==1)
        {
            t.update(1,dfn[x],y);
        }
        else
        {
            printf("%d\n",query(x,y));
        }
    }
    return 0;
}
